        return this.masterBarLookup.get(bar.index)!!
    }
    
    /**
     * Gets the start time in midi ticks for a given masterbar at which the masterbar is played the first time.
     * @param bar The masterbar to find the time period for.
     */
    public fun getMasterBarStart(bar: com.omnifret.gplayer.model.MasterBar): Double{
        if (!this.masterBarLookup.has(bar.index))
        {
            return 0.0
        }
        return this.masterBarLookup.get(bar.index)!!.start
    }
    
    /**
     * Gets the start time in midi ticks for a given beat at which the masterbar is played the first time.
     * @param beat The beat to find the time period for.
     */
    public fun getBeatStart(beat: com.omnifret.gplayer.model.Beat): Double{
        if (!this.masterBarLookup.has(beat.voice.bar.index))
        {
            return 0.0
        }
        return this.masterBarLookup.get(beat.voice.bar.index)!!.start + beat.playbackStart
    }
    
    /**
     * Adds a new  to the lookup table.
     * @param masterBar The item to add.
     */
    public fun addMasterBar(masterBar: com.omnifret.gplayer.midi.MasterBarTickLookup): Unit{
        this.masterBars.push(masterBar)
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this._currentMasterBar)))
        {
            masterBar.previousMasterBar = this._currentMasterBar!!
            this._currentMasterBar!!.nextMasterBar = masterBar
        }
        this._currentMasterBar = masterBar
        if (!this.masterBarLookup.has(masterBar.masterBar.index))
        {
            this.masterBarLookup.set(masterBar.masterBar.index, masterBar)
        }
    }
    
    /**
     */
    public fun addBeat(beat: com.omnifret.gplayer.model.Beat, start: Double, duration: Double): Unit{
        var currentMasterBar: com.omnifret.gplayer.midi.MasterBarTickLookup? = this._currentMasterBar
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(currentMasterBar)))
        {
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(start < 0 && com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(currentMasterBar!!.previousMasterBar))))
            {
                var relativeMasterBarEnd: Double = currentMasterBar!!.previousMasterBar!!.end - currentMasterBar!!.previousMasterBar!!.start
                var previousStart: Double = relativeMasterBarEnd + start
                var previousEnd: Double = previousStart + duration
                currentMasterBar!!.previousMasterBar!!.addBeat(beat, previousStart, previousStart, duration)
                if (previousEnd > relativeMasterBarEnd)
                {
                    var overlapDuration: Double = duration + start
                    currentMasterBar!!.addBeat(beat, start, 0.0, overlapDuration)
                }
            }
            else 
            {
                currentMasterBar!!.addBeat(beat, start, start, duration)
            }
        }
    }
    
    public constructor()
}

/**
 * Describes how a cursor should be moving.
 */
public enum class MidiTickLookupFindBeatResultCursorMode(override val value: Int): com.omnifret.gplayer.core.IGPlayerEnum
{
    /**
     * Unknown/Undetermined mode. Should not happen on user level.
     */
    Unknown(0),
    /**
     * The cursor should animate to the next beat.
     */
    ToNextBext(1),
    ToEndOfBar(2),
    /**
     * The cursor should animate to the end of the **beat** (typically on repeats and jumps)
     * (this is named end of bar historically)
     */
    ToEndOfBeat(3);
    companion object : com.omnifret.gplayer.core.IGPlayerEnumCompanion<MidiTickLookupFindBeatResultCursorMode>{
        public override val values = arrayOf(Unknown, ToNextBext, ToEndOfBar, ToEndOfBeat) 
        public override fun fromValue(v:Double): MidiTickLookupFindBeatResultCursorMode{
            return when(v.toInt()){
                Unknown.value -> Unknown
                ToNextBext.value -> ToNextBext
                ToEndOfBar.value -> ToEndOfBar
                ToEndOfBeat.value -> ToEndOfBeat
                else -> throw ClassCastException("No enum with value $v found")}
        }
    }
}

/**
 * Represents the results of searching the currently played beat.
 */
@kotlin.contracts.ExperimentalContracts
@kotlin.ExperimentalUnsignedTypes
public class MidiTickLookupFindBeatResult
{
    /**
     * Gets or sets the beat that is currently played and used for the start
     * position of the cursor animation.
     */
    public lateinit var beat: com.omnifret.gplayer.model.Beat
    
    /**
     * Gets or sets the parent MasterBarTickLookup to which this beat lookup belongs to.
     */
    public var masterBar: com.omnifret.gplayer.midi.MasterBarTickLookup
    
    /**
     * Gets or sets the related beat tick lookup.
     */
    public lateinit var beatLookup: com.omnifret.gplayer.midi.BeatTickLookup
    
    /**
     * Gets or sets the beat that will be played next.
     */
    public var nextBeat: com.omnifret.gplayer.midi.MidiTickLookupFindBeatResult? = null
    
    
    /**
     * Gets or sets the duration in midi ticks how long this lookup is valid.
     */
    public var tickDuration: Double = 0.0
    
    
    /**
     * Gets or sets the duration in milliseconds how long this lookup is valid.
     */
    public var duration: Double = 0.0
    
    
    /**
     * The mode how the cursor should be handled.
     */
    public var cursorMode: com.omnifret.gplayer.midi.MidiTickLookupFindBeatResultCursorMode = com.omnifret.gplayer.midi.MidiTickLookupFindBeatResultCursorMode.Unknown
    
    
    public val start: Double
    get(){
        return this.masterBar.start + this.beatLookup.start
    }
    
    public val end: Double
    get(){
        return this.start + this.tickDuration
    }
    
    public constructor(masterBar: com.omnifret.gplayer.midi.MasterBarTickLookup){
        this.masterBar = masterBar
    }
    
    public fun calculateDuration(): Unit{
        if (this.masterBar.tempoChanges.length == 1.0)
        {
            this.duration = com.omnifret.gplayer.midi.MidiUtils.ticksToMillis(this.tickDuration, this.masterBar.tempoChanges[(0).toInt()].tempo)
        }
        else 
        {
            var millis: Double = 0.0
            var currentTick: Double = this.start
            var currentTempo: Double = this.masterBar.tempoChanges[(0).toInt()].tempo
            var endTick: Double = this.end
            for (change in this.masterBar.tempoChanges)
            {
                if (change.tick < currentTick)
                {
                    currentTempo = change.tempo
                }
                else if (change.tick > endTick)
                {
                    break
                }
                else 
                {
                    millis += com.omnifret.gplayer.midi.MidiUtils.ticksToMillis(change.tick - currentTick, currentTempo)
                    currentTempo = change.tempo
                    currentTick = change.tick
                }
            }
            if (endTick > currentTick)
            {
                millis += com.omnifret.gplayer.midi.MidiUtils.ticksToMillis(endTick - currentTick, currentTempo)
            }
            this.duration = millis
        }
    }
    
}

@kotlin.contracts.ExperimentalContracts
@kotlin.ExperimentalUnsignedTypes
internal class TrackLookupBeatVisibilityChecker: com.omnifret.gplayer.midi.IBeatVisibilityChecker
{
    private var _lookup: com.omnifret.gplayer.core.ecmaScript.Set<Double>
    
    public constructor(lookup: com.omnifret.gplayer.core.ecmaScript.Set<Double>){
        this._lookup = lookup
    }
    
    /**
     */
    public override fun isVisible(beat: com.omnifret.gplayer.model.Beat): Boolean{
        return this._lookup.has(beat.voice.bar.staff.track.index)
    }
    
}

